import React, { useState } from 'react';

export default function AnalysisPanel({ result, loading }) {
  const [tab, setTab] = useState('output');
  const [hints, setHints] = useState(new Set());
  const toggle = i => setHints(p => { const n = new Set(p); n.has(i) ? n.delete(i) : n.add(i); return n; });

  if (!result && !loading) return <div className="ws-pan"><div className="tabs"><button className="tab on">Output</button></div><div className="pan"><div className="empty"><span style={{fontSize:'2rem'}}>🧠</span><p>Run or Analyze your code to see results</p><p style={{fontSize:'.78rem'}}>▶ Run = execute only &nbsp;|&nbsp; 🧠 Analyze = full WHY pipeline</p></div></div></div>;

  const a = result?.whyAnalysis || {};
  const tabs = [{id:'output',l:'Output'},{id:'why',l:'WHY Analysis'},{id:'tests',l:'Tests',c:result?.testCases?.length},{id:'delta',l:'Delta'}];

  return (
    <div className="ws-pan">
      <div className="tabs">{tabs.map(t=><button key={t.id} className={`tab ${tab===t.id?'on':''}`} onClick={()=>setTab(t.id)}>{t.l}{t.c!=null&&<span className="cnt">{t.c}</span>}</button>)}</div>
      <div className="pan">
        {loading && <div className="loading" style={{flexDirection:'column',gap:14}}><div className="spinner" style={{width:28,height:28}}/><span>Running full analysis pipeline...</span><div style={{fontSize:'.75rem',color:'var(--text-3)',textAlign:'center'}}>Execution → Static Analysis → Test Cases → AI Reasoning → Profiling</div></div>}

        {/* OUTPUT TAB */}
        {!loading && tab==='output' && result && <div className="fade">
          <div className={`out ${result.executionResult?.stderr?'err':result.executionResult?.status==='Accepted'?'ok':''}`}>{result.executionResult?.stdout||result.executionResult?.stderr||'(no output)'}</div>
          <div className="out-m"><span>Status: <b style={{color:result.executionResult?.status==='Accepted'?'var(--ok)':'var(--err)'}}>{result.executionResult?.status}</b></span><span>Time: <b>{result.executionResult?.time}s</b></span><span>Memory: <b>{result.executionResult?.memory}</b></span>{result.processingTime&&<span>Pipeline: <b>{(result.processingTime/1000).toFixed(1)}s</b></span>}</div>
          {result.staticAnalysis?.length>0&&<div style={{marginTop:16}}><h4 style={{fontSize:'.72rem',fontWeight:700,color:'var(--text-3)',textTransform:'uppercase',marginBottom:8}}>Static Analysis ({result.staticAnalysis.length})</h4>{result.staticAnalysis.map((i,j)=><div key={j} className={`iss ${i.severity}`}><div><span style={{fontFamily:'var(--mono)',fontSize:'.72rem',marginRight:8}}>L{i.line}</span>{i.message}</div>{i.suggestion&&<div className="iss-sug">💡 {i.suggestion}</div>}</div>)}</div>}
          {result.pipelineSteps&&<div style={{marginTop:14,fontSize:'.72rem',color:'var(--text-3)'}}>Pipeline: {result.pipelineSteps.join(' → ')}</div>}
        </div>}

        {/* WHY ANALYSIS TAB */}
        {!loading && tab==='why' && result && <div className="fade">
          {a.confidence&&<div className="a-sec"><h3>🎯 Analysis Confidence</h3><div className="conf-row"><span className="conf-val" style={{color:(a.confidence.analysisConfidence||0)>.7?'var(--ok)':(a.confidence.analysisConfidence||0)>.4?'var(--warn)':'var(--err)'}}>{Math.round((a.confidence.analysisConfidence||0)*100)}%</span><div className="conf-bar"><div className={`conf-fill ${(a.confidence.analysisConfidence||0)>.7?'hi':(a.confidence.analysisConfidence||0)>.4?'md':'lo'}`} style={{width:`${(a.confidence.analysisConfidence||0)*100}%`}}/></div></div>{a.confidence.uncertainAreas?.length>0&&<p style={{marginTop:6,fontSize:'.78rem'}}>Uncertain: {a.confidence.uncertainAreas.join(', ')}</p>}{a.confidence.dataSourcesUsed?.length>0&&<div style={{marginTop:4,fontSize:'.72rem',color:'var(--text-3)'}}>Sources: {a.confidence.dataSourcesUsed.map(s=><span key={s} className="tag tag-c" style={{marginLeft:2}}>{s}</span>)}</div>}</div>}

          {a.cognitiveTaxonomy&&<div className="a-sec"><h3>🏷️ Error Classification</h3><div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:6}}><span className="tag tag-e">{a.cognitiveTaxonomy.errorType}</span><span className="tag tag-c">{a.cognitiveTaxonomy.category}</span>{a.cognitiveTaxonomy.confidence&&<span className="tag tag-w">{Math.round(a.cognitiveTaxonomy.confidence*100)}%</span>}</div>{a.cognitiveTaxonomy.pattern&&<p>{a.cognitiveTaxonomy.pattern}</p>}{a.cognitiveTaxonomy.subPatterns?.length>0&&<ul>{a.cognitiveTaxonomy.subPatterns.map((s,i)=><li key={i}>{s}</li>)}</ul>}</div>}

          {a.thinkingComparison&&a.thinkingComparison.approachMatch>0&&<div className="a-sec"><h3>🔍 Thinking vs Reality</h3><div style={{display:'flex',gap:14,flexWrap:'wrap',marginBottom:6}}><div style={{textAlign:'center'}}><div style={{fontSize:'1.2rem',fontWeight:800,color:a.thinkingComparison.approachMatch>60?'var(--ok)':'var(--warn)'}}>{a.thinkingComparison.approachMatch}%</div><div style={{fontSize:'.68rem',color:'var(--text-3)'}}>Approach</div></div><div style={{textAlign:'center'}}><div style={{fontSize:'1.2rem',fontWeight:800,color:a.thinkingComparison.edgeCasesCovered>60?'var(--ok)':'var(--err)'}}>{a.thinkingComparison.edgeCasesCovered}%</div><div style={{fontSize:'.68rem',color:'var(--text-3)'}}>Edge Cases</div></div><div style={{textAlign:'center'}}><div style={{fontSize:'1.2rem',fontWeight:800,color:a.thinkingComparison.complexityMatch?'var(--ok)':'var(--err)'}}>{a.thinkingComparison.complexityMatch?'✓':'✗'}</div><div style={{fontSize:'.68rem',color:'var(--text-3)'}}>Complexity</div></div></div>{a.thinkingComparison.gaps?.length>0&&<><p style={{fontSize:'.78rem',fontWeight:600,marginTop:6}}>Gaps:</p><ul>{a.thinkingComparison.gaps.map((g,i)=><li key={i}>{g}</li>)}</ul></>}</div>}

          {a.hintsProvided?.length>0&&<div className="a-sec"><h3>💡 Hints (Try Before Solution)</h3>{a.hintsProvided.map((h,i)=><div key={i} className={`hint ${hints.has(i)?'':'hid'}`} onClick={()=>toggle(i)}><div className="hint-lv">{h.level===1?'🟢 Subtle':h.level===2?'🟡 Medium':'🔴 Direct'}{!hints.has(i)&&' — click to reveal'}</div><div className="hint-t">{h.hint}</div></div>)}</div>}

          <Sec t="📋 Mistake Summary" c={a.mistakeSummary}/>
          <Sec t="❓ Why It's Wrong" c={a.whyWrong}/>
          <Sec t="💭 Your Thought Process" c={a.thoughtProcess}/>
          <Sec t="🔍 Root Cause" c={a.rootCause}/>
          {a.failingCases?.length>0&&<div className="a-sec"><h3>💥 Failing Cases</h3><ul>{a.failingCases.map((c,i)=><li key={i}>{c}</li>)}</ul></div>}
          {a.lineByLine?.length>0&&<div className="a-sec"><h3>📝 Line-by-Line</h3>{a.lineByLine.map((l,i)=><div key={i} className={`ln ${l.hasIssue?'bad':''}`}><span className="ln-n">L{l.line}</span><div>{l.code&&<code style={{display:'block',marginBottom:2}}>{l.code}</code>}<span>{l.explanation}</span></div></div>)}</div>}
          <Sec t="✅ Correct Logic" c={a.correctLogic}/>
          {a.correctCode&&<Code t="✅ Correct Code" c={a.correctCode}/>}
          {a.correctCodeWalkthrough&&<Sec t="📖 Walkthrough" c={a.correctCodeWalkthrough}/>}
          {a.optimizedCode&&<div className="a-sec"><h3>⚡ Optimized {a.optimizedComplexity&&<span className="tag tag-c" style={{marginLeft:6}}>{a.optimizedComplexity}</span>}</h3><pre>{a.optimizedCode}</pre></div>}
          <Sec t="🧠 Mental Model" c={a.mentalModel}/>
          {a.multipleApproaches?.length>0&&<div className="a-sec"><h3>🔄 Multiple Approaches</h3>{a.multipleApproaches.map((ap,i)=><div key={i} className="ap"><div className="ap-h"><span className="ap-n">{ap.name}</span><div><span className="ap-c">{ap.complexity}</span>{ap.spaceComplexity&&<span className="ap-c" style={{marginLeft:6}}>Space: {ap.spaceComplexity}</span>}</div></div><p style={{fontSize:'.85rem',marginBottom:6}}>{ap.description}</p>{(ap.pros?.length>0||ap.cons?.length>0)&&<div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,fontSize:'.78rem'}}>{ap.pros?.length>0&&<div><div style={{fontWeight:700,color:'var(--ok)',fontSize:'.7rem'}}>✓ PROS</div><ul style={{paddingLeft:14}}>{ap.pros.map((p,j)=><li key={j}>{p}</li>)}</ul></div>}{ap.cons?.length>0&&<div><div style={{fontWeight:700,color:'var(--err)',fontSize:'.7rem'}}>✗ CONS</div><ul style={{paddingLeft:14}}>{ap.cons.map((c,j)=><li key={j}>{c}</li>)}</ul></div>}</div>}{ap.code&&<pre style={{marginTop:6}}>{ap.code}</pre>}</div>)}</div>}
        </div>}

        {/* TESTS TAB */}
        {!loading && tab==='tests' && result && <div className="fade">
          {result.testCases?.length>0&&<div style={{marginBottom:10,fontSize:'.82rem',color:'var(--text-3)'}}>{result.testCases.filter(t=>t.passed).length}/{result.testCases.length} passing</div>}
          {(result.testCases||[]).map((t,i)=><div key={i} className={`tc ${t.passed?'pass':'fail'}`}><div style={{flex:1,minWidth:0}}><div className="tc-in">Input: "{t.input||'(empty)'}" → {t.actualOutput||'(none)'}</div>{t.expectedOutput&&<div style={{fontSize:'.75rem',color:'var(--text-3)',marginTop:1}}>Expected: {t.expectedOutput}</div>}<div className="tc-d">{t.description||t.category}</div></div><span className={`badge ${t.passed?'pass':'fail'}`}>{t.passed?'PASS':'FAIL'}</span></div>)}
          {!result.testCases?.length&&<div className="empty"><p>No test cases</p></div>}
        </div>}

        {/* DELTA TAB */}
        {!loading && tab==='delta' && result && <div className="fade">
          {result.deltaAnalysis&&result.deltaAnalysis.overallProgress!=='first_attempt'?<>
            <div style={{textAlign:'center',marginBottom:14}}><span className={`tag ${result.deltaAnalysis.overallProgress==='improved'?'tag-s':result.deltaAnalysis.overallProgress==='regressed'?'tag-e':'tag-w'}`} style={{fontSize:'.85rem',padding:'5px 14px'}}>{result.deltaAnalysis.overallProgress==='improved'?'📈 IMPROVED':result.deltaAnalysis.overallProgress==='regressed'?'📉 REGRESSED':'➡️ SAME'}</span></div>
            {result.deltaAnalysis.improvements?.length>0&&<div className="d-sec imp"><h4>✅ Improvements</h4>{result.deltaAnalysis.improvements.map((x,i)=><div key={i} className="d-item">✓ {x}</div>)}</div>}
            {result.deltaAnalysis.regressions?.length>0&&<div className="d-sec reg"><h4>⚠️ Regressions</h4>{result.deltaAnalysis.regressions.map((x,i)=><div key={i} className="d-item">✗ {x}</div>)}</div>}
            {result.deltaAnalysis.unchanged?.length>0&&<div className="d-sec unc"><h4>➡️ Unchanged</h4>{result.deltaAnalysis.unchanged.map((x,i)=><div key={i} className="d-item">— {x}</div>)}</div>}
          </>:<div className="empty"><span style={{fontSize:'1.5rem'}}>🔄</span><p>Submit multiple attempts to see delta analysis</p></div>}
        </div>}
      </div>
    </div>
  );
}

function Sec({t,c}){if(!c)return null;return<div className="a-sec"><h3>{t}</h3><p style={{whiteSpace:'pre-wrap'}}>{c}</p></div>}
function Code({t,c}){if(!c)return null;return<div className="a-sec"><h3>{t}</h3><pre>{c}</pre></div>}
